    def sound(self): print('Generic sound')
class Dog(Animal):
    def sound(self): print('Woof')  # overrides Animal.sound()

class RECTANGLE:
    def __init__(self,l,b): self.l=l; self.b=b
    def area(self): return self.l*self.b
    def perimeter(self): return 2*(self.l+self.b)

