stack=[]
def PUSH(s,x): s.append(x)
def POP(s):
    if s: return s.pop()
    print('Underflow')

queue=[]
def enqueue(q,x): q.append(x)
def dequeue(q):
    if q: return q.pop(0)
    print('Queue Empty')

def linearSearch(lst,key):
    for i in range(len(lst)):
        if lst[i]==key: return i
    return -1

def bubbleSort(a):
    n=len(a)
    for i in range(n-1):
        for j in range(n-i-1):
            if a[j]>a[j+1]: a[j],a[j+1]=a[j+1],a[j]

def isPrime(n):
    if n<2: return False
    for i in range(2,int(n**0.5)+1):
        if n%i==0: return False
    return True

def freq(lst):
    d={}
    for x in lst:
        d[x]=d.get(x,0)+1
    return d

